//帮别人调
#include<bits/stdc++.h>
#define int long long
#define ci const int
#define elif else if

using namespace std;

ci e=510;
char s_a[e],s_b[e];
int a[e],b[e],c[e],flag;

signed main(){
    ios::sync_with_stdio(0),
    cin.tie(0),cout.tie(0);

    cin>>s_a+1>>s_b+1;

    a[0]=strlen(s_a+1),b[0]=strlen(s_b+1),c[0]=max(a[0],b[0]);
    for(int i=1;i<=a[0];i++)a[i]=s_a[a[0]-i+1]-'0';
    for(int i=1;i<=b[0];i++)b[i]=s_b[b[0]-i+1]-'0';
    for(int i=1;i<=c[0];i++){
        c[i]+=a[i]+b[i];
        if(c[i]>=10)c[i+1]++,c[i]-=10;//大于等于10 
    }
    if(c[c[0]+1])c[0]++;
    for(int i=c[0];i>0;i--){
        if(!flag&&!c[i])continue;
        cout<<c[i],flag=1;
    }
    if(!flag)cout<<0;

    return 0;//保AC
}
